// ════════════════════════════════════════════════════
// ⚙️  CONFIGURACIÓN — editá solo este nodo al instalar
// ════════════════════════════════════════════════════
return [{ json: {

  // ── n8n DataTable (estado de sesión de usuarios) ──
  tablaEstadoUsuarioId: "lQx8OcjpMQhcePpg",

  // ── Google Drive ──────────────────────────────────
  // driveId: "My Drive" para drive personal; para Shared Drive ponés el ID del drive
  driveId: "My Drive",
  carpetaTempDriveId: "1q6QGqzRjJ5v6tBBL8maq25ZGEHJ0ZeyU",

  // ── Google Sheets: planilla de obras activas ─────
  sheetObrasId: "1_HaEtyhS5SOo6RmVqhSIkXcNRNuNQsrcBr8ngSozV9s",

  // ── Modelo de IA (Mistral) ────────────────────────
  // Opciones: "mistral-ocr-latest", "pixtral-large-latest", "pixtral-12b-2409"
  modeloMistralOcr:  "mistral-ocr-latest",
  // Opciones chat: "mistral-large-latest", "mistral-small-latest", "open-mixtral-8x22b"
  modeloMistralChat: "mistral-large-latest",

  // ── Sesión ────────────────────────────────────────
  // Minutos de inactividad antes de resetear la sesión del usuario
  tiempoSesionMin: 10,

  // ── Lógica de negocio ─────────────────────────────
  // Caja que se usa por defecto para egresos e ingresos
  cajaDefault: "CCH",

  // ── Acceso: Telegram user IDs permitidos ─────────
  // Dejá el array vacío [] para permitir a todos
  usuariosPermitidos: [],

  // ── Columnas a escribir en Google Sheets ─────────
  // Para agregar una columna nueva: sumá un objeto { columna, campo }
  // - columna: nombre exacto del encabezado en la sheet
  // - campo:   nombre del campo en los datos extraídos de la factura
  //            Campos disponibles: tipo, caja, tarea, concepto, proveedor,
  //            reciboNro, fecha, ars, id, or, comprobanteUrl
  // - esHyperlink (opcional): true → genera =HYPERLINK(url, texto)
  //   requiere también definir campoUrl con el campo que tiene la URL
  columnasGasto: [
    { columna: "TIPO",      campo: "tipo" },
    { columna: "CAJA",      campo: "caja" },
    { columna: "TAREA",     campo: "tarea" },
    { columna: "CONCEPTO",  campo: "concepto" },
    { columna: "PROVEEDOR", campo: "proveedor" },
    { columna: "RECIBO Nº", campo: "reciboNro", esHyperlink: true, campoUrl: "comprobanteUrl" },
    { columna: "FECHA",     campo: "fecha" },
    { columna: "ARS",       campo: "ars" },
    { columna: "ID",        campo: "id" },
    { columna: "OR",        campo: "or" },
  ],

}}];

const msg = $('Bot Tetris1').first().json.message;
return [{ json: {
  texto: msg.text || msg.caption || "",
  chatId: String(msg.chat.id),
  message: msg
}}];

const input = $json || {};
const step = input.step || "idle";
let expired = false;
if (input.updatedAt && step !== "idle") {
  const diffMin = (Date.now() - new Date(input.updatedAt).getTime()) / 60000;
  if (diffMin > $('⚙️ Config').first().json.tiempoSesionMin) expired = true;
}
return [{ json: { ...input, step: expired ? "idle" : step, expired } }];

const upload = $input.first().json;
const fileData = $('Get a file').first();
const comprobanteUrl = upload.webViewLink || upload.webContentLink || `https://drive.google.com/file/d/${upload.id}/view`;
return [{ json: { comprobanteUrl, uploadedFileId: upload.id }, binary: fileData.binary }];

let raw = $json.output || JSON.stringify($json);
if (typeof raw !== 'string') raw = JSON.stringify(raw);
raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();
const data = JSON.parse(raw);
const comprobanteUrl = $('Preparar contexto obra').first().json.comprobanteUrl || '';
const uploadedFileId = $('Preparar contexto obra').first().json.uploadedFileId || '';
return [{ json: {
  tarea: data.tarea || '',
  concepto: data.concepto || '',
  proveedor: data.proveedor || '',
  reciboNro: data.reciboNro || data.id || '',
  fecha: data.fecha || '',
  ars: Number(data.ars || 0),
  comprobanteUrl,
  uploadedFileId,
  unclear: data.unclear === true
}}];

const expenseData = $('Normalizar extracción').first().json;
const obras = $input.all().map(i => i.json);

const unclearNote = expenseData.unclear
  ? '\n⚠️ Imagen poco clara. Igualmente indicá la obra para archivarla en revisión.\n'
  : '';

let obraLines = '';
obras.forEach((o, i) => { obraLines += `${i + 1} · ${o.Obra}\n`; });

const mensaje = [
  '📋 Comprobante recibido:',
  `Proveedor: ${expenseData.proveedor || '(no detectado)'}`,
  `Monto: $${expenseData.ars || '?'}`,
  `Fecha: ${expenseData.fecha || '?'}`,
  `Concepto: ${expenseData.concepto || '?'}`,
  unclearNote,
  '¿A qué obra pertenece este comprobante?\n',
  obraLines.trim(),
  '\n0 · Cancelar',
  '\nRespondé con el número.'
].join('\n');

return [{ json: { mensaje, obras, expenseData } }];

const text = ($('Preparar entrada').first().json.texto || '').trim();
const state = $json;
const obras = JSON.parse(state.obrasJson || '[]');

if (text === '0') {
  return [{ json: { valid: false, cancel: true, message: '' } }];
}

const num = parseInt(text, 10);
if (isNaN(num) || num < 1 || num > obras.length) {
  return [{ json: { valid: false, cancel: false,
    message: `⚠️ Número inválido. Respondé del 1 al ${obras.length} o 0 para cancelar.` } }];
}

const obraSeleccionada = obras[num - 1];
return [{ json: {
  valid: true,
  cancel: false,
  obraSeleccionada
} }];

const state        = $('Consultar estado usuario').first().json;
const tipoData     = $('Validar tipo').first().json;
const pendingData  = JSON.parse(state.pendingExpenseJson || '{}');
const operationType = tipoData.operationType;
const interesado   = state.Interesado || '';

let tipo, caja;
if (operationType === 'ingreso')     { tipo = 'Ingreso'; caja = $('⚙️ Config').first().json.cajaDefault; }
else if (operationType === 'doble')  { tipo = 'Doble';   caja = interesado; }
else                                 { tipo = 'Egreso';  caja = $('⚙️ Config').first().json.cajaDefault; }

return [{ json: {
  tipo, caja,
  id: '', or: '',
  tarea:           pendingData.tarea        || '',
  concepto:        pendingData.concepto     || '',
  proveedor:       pendingData.proveedor    || '',
  reciboNro:       pendingData.reciboNro    || '',
  fecha:           pendingData.fecha        || '',
  ars:             Number(pendingData.ars   || 0),
  comprobanteUrl:  pendingData.comprobanteUrl || '',
  unclear:         pendingData.unclear === true,
  operationType,
  selectedObra:          state.selectedObra          || '',
  selectedSpreadsheetId: state.selectedSpreadsheetId || '',
  selectedSheetName:     state.selectedSheetName     || '',
  folderFacturasId:      state.folderFacturasId      || '',
  folderRevisionId:      state.folderRevisionId      || '',
  selectedInteresado:    interesado,
  uploadedFileId:        state.uploadedFileId        || ''
} }];

const gasto = $('Aplicar asignación').item.json;
const operationType = gasto.operationType || 'egreso';
const interesado = gasto.selectedInteresado || '';
const ars = Math.abs(Number(gasto.ars || 0));

if (operationType === 'doble') {
  return [
    { json: { ...gasto, tipo: 'Ingreso', ars: ars, caja: interesado } },
    { json: { ...gasto, tipo: 'Egreso', ars: -ars, caja: interesado } }
  ];
} else if (operationType === 'ingreso') {
  return [{ json: { ...gasto, tipo: 'Ingreso', ars: ars } }];
} else {
  return [{ json: { ...gasto, tipo: 'Egreso', ars: -ars } }];
}

