// Lee la definición de columnas del Config y arma la fila para la sheet
// Procesa TODOS los ítems (el caso 'doble' genera 2 registros)
const cfg = $('⚙️ Config').first().json;

return $input.all().map(item => {
  const gasto = item.json;
  const row = {};
  for (const col of cfg.columnasGasto) {
    if (col.esHyperlink && col.campoUrl) {
      const url  = gasto[col.campoUrl] || '';
      const text = gasto[col.campo]    || '';
      row[col.columna] = url ? `=HYPERLINK("${url}","${text}")` : text;
    } else {
      const val = gasto[col.campo];
      row[col.columna] = (val !== undefined && val !== null) ? val : '';
    }
  }
  return { json: row };
});

const text = ($('Preparar entrada').first().json.texto || '').trim();

if (text === '0') {
  return [{ json: { valid: false, cancel: true, message: '' } }];
}

const map = { '1': 'egreso', '2': 'ingreso', '3': 'doble' };
const operationType = map[text];

if (!operationType) {
  return [{ json: { valid: false, cancel: false,
    message: '⚠️ Opción inválida. Respondé 1 (Egreso), 2 (Ingreso), 3 (Pago cliente) o 0 para cancelar.' } }];
}

return [{ json: { valid: true, cancel: false, operationType } }];
